import type { Meta, StoryObj } from '@storybook/react-vite';
import { expect } from 'storybook/test';
import ContactForm from './ContactForm';

const meta = {
  component: ContactForm,
} satisfies Meta<typeof ContactForm>;

export default meta;
type Story = StoryObj<typeof meta>;

export const Default: Story = {
  render: () => <ContactForm />,
  play: async ({ canvas }) => {
    const inputs = canvas.queryAllByRole('textbox');
    await expect(inputs.length).toBeGreaterThan(0);
    await expect(
      canvas.getByRole('button', { name: /submit/i })
    ).toBeVisible();
  },
};

export const WithFormInput: Story = {
  render: () => <ContactForm />,
  play: async ({ canvas, userEvent }) => {
    const inputs = canvas.queryAllByRole('textbox');
    if (inputs.length >= 3) {
      const firstNameInput = inputs[0] as HTMLInputElement;
      const lastNameInput = inputs[1] as HTMLInputElement;
      const emailInput = inputs[2] as HTMLInputElement;

      await userEvent.type(firstNameInput, 'John', { delay: 30 });
      await userEvent.type(lastNameInput, 'Doe', { delay: 30 });
      await userEvent.type(emailInput, 'john@example.com', { delay: 30 });

      await expect(firstNameInput).toHaveValue('John');
      await expect(lastNameInput).toHaveValue('Doe');
      await expect(emailInput).toHaveValue('john@example.com');
    }
  },
};

